const postCount = items.length;
console.log(`[DEBUG] Fetch WP Posts returned ${postCount} posts`);

items.slice(0, 5).forEach((item, index) => {
  const post = item.json ?? {};
  console.log(
    `[DEBUG] Post ${index + 1}: id=${post.id} slug=${post.slug} date_gmt=${post.date_gmt}`,
  );
});

return items;

const LOOKBACK_MINUTES = 70;
const now = new Date();
const cutoffMs = now.getTime() - LOOKBACK_MINUTES * 60 * 1000;

return items
  .filter((item) => {
    const post = item.json ?? {};
    const dateGmt = post.date_gmt;

    if (!dateGmt) {
      return false;
    }

    const publishedMs = Date.parse(`${dateGmt}Z`);
    return Number.isFinite(publishedMs) && publishedMs > cutoffMs;
  })
  .map((item) => ({
    json: {
      ...(item.json ?? {}),
      detectedAtUtc: now.toISOString(),
    },
  }));

console.log('[DEBUG] Deduplication history cleared for workflow scope.');

return [{
  json: {
    maintenanceAction: 'clearDeduplicationHistory',
    scope: 'workflow',
    clearedAtUtc: new Date().toISOString(),
  },
}];

const detectedItems = $('Detect New Posts (date_gmt)').all();
const detectedIds = detectedItems
  .map((item) => item.json?.id)
  .filter((value) => value !== undefined && value !== null);
const keptIds = items
  .map((item) => item.json?.id)
  .filter((value) => value !== undefined && value !== null);
const keptSet = new Set(keptIds);
const duplicateIds = detectedIds.filter((id) => !keptSet.has(id));

console.log(
  `[DEBUG] Deduplicate summary: detected=${detectedIds.length}, kept=${keptIds.length}, duplicates=${duplicateIds.length}`,
);

if (keptIds.length > 0) {
  console.log(`[DEBUG] New post IDs after dedupe: ${keptIds.join(', ')}`);
}

if (duplicateIds.length > 0) {
  console.log(`[DEBUG] Duplicate post IDs skipped: ${duplicateIds.join(', ')}`);
}

return items;

const TAG_RE = /<[^>]*>/g;
const WHITESPACE_RE = /\s+/g;
const ENTITY_MAP = {
  '&amp;': '&',
  '&lt;': '<',
  '&gt;': '>',
  '&quot;': '"',
  '&#039;': "'",
  '&nbsp;': ' ',
};

function decodeEntities(value) {
  return value.replace(/&(amp|lt|gt|quot|#039|nbsp);/g, (entity) => ENTITY_MAP[entity] ?? entity);
}

function stripHtml(value) {
  if (typeof value !== 'string' || !value) {
    return '';
  }

  const text = decodeEntities(value.replace(TAG_RE, ' '));
  return text.replace(WHITESPACE_RE, ' ').trim();
}

return items.map((item) => {
  const post = item.json ?? {};
  const embedded = post._embedded ?? {};
  const mediaItems = Array.isArray(embedded['wp:featuredmedia']) ? embedded['wp:featuredmedia'] : [];
  const featuredMedia = mediaItems[0] ?? {};
  const titleRaw = post.title;
  const excerptRaw = post.excerpt;
  const title = stripHtml(typeof titleRaw === 'object' ? titleRaw?.rendered : titleRaw);
  const excerpt = stripHtml(typeof excerptRaw === 'object' ? excerptRaw?.rendered : excerptRaw);
  const imageUrl = typeof featuredMedia === 'object' ? featuredMedia.source_url ?? null : null;

  return {
    json: {
      ...post,
      titleText: title,
      excerptText: excerpt,
      topic: title,
      content: excerpt,
      postUrl: post.link,
      imageUrl,
      hasFeaturedImage: Boolean(imageUrl),
    },
  };
});

function enforceConstraints(raw) {
  const URL_RE = /https?:\/\/\S+/g;
  let message = raw.trim();

  const urls = message.match(URL_RE) || [];
  const postUrl = urls[urls.length - 1] || '';

  if (!message.includes('#n8n')) {
    if (postUrl && message.endsWith(postUrl)) {
      const body = message.slice(0, message.lastIndexOf(postUrl)).trimEnd();
      message = body + ' #n8n ' + postUrl;
    } else {
      message = message.trimEnd() + ' #n8n';
      if (postUrl) {
        message += ' ' + postUrl;
      }
    }
  }

  if (message.length > 280) {
    let body = message;
    if (postUrl) {
      body = body.replace(' ' + postUrl, '').replace(postUrl, '');
    }
    body = body.replace(/ #n8n/g, '').replace(/#n8n /g, '').replace(/#n8n/g, '').trim();
    const tail = postUrl ? ' #n8n ' + postUrl : ' #n8n';
    const maxBody = 280 - tail.length;
    message = body.slice(0, maxBody).trimEnd() + tail;
  }

  return message;
}

return items.map((item) => {
  const post = item.json ?? {};

  let raw = '';
  if (typeof post.message === 'string') {
    raw = post.message;
  } else if (typeof post.message?.content === 'string') {
    raw = post.message.content;
  } else if (post.choices?.[0]?.message?.content) {
    raw = post.choices[0].message.content;
  }

  const socialMessage = enforceConstraints(raw);
  const socialMessageValid = socialMessage.length <= 280 && socialMessage.includes('#n8n');

  console.log(`[DEBUG] Validate AI message: length=${socialMessage.length}, valid=${socialMessageValid}`);
  if (!socialMessageValid) {
    console.warn(`[WARN] AI message constraint violation: "${socialMessage}"`);
  }

  return {
    json: {
      ...post,
      socialMessage,
      socialMessageLength: socialMessage.length,
      socialMessageValid,
    },
  };
});

items.forEach((item, index) => {
  const post = item.json ?? {};
  console.log(
    `[DEBUG] AI message [${index + 1}/${items.length}] post_id=${post.id} valid=${post.socialMessageValid} length=${post.socialMessageLength}`,
  );
  console.log(`[DEBUG] socialMessage: ${post.socialMessage}`);
});

return items;
